import json
from datetime import datetime

def generate_report(analysis, test_results, lint_results):
    report = {
        'timestamp': datetime.now().isoformat(),
        'project_analysis': analysis,
        'test_results': test_results,
        'lint_results': lint_results,
        'summary': {
            'syntax_issues': len(analysis.get('syntax_issues', [])),
            'tests_passed': test_results.get('passed', False) if 'error' not in test_results else False,
            'lint_clean': lint_results.get('clean', False) if 'error' not in lint_results else False
        }
    }
    return report

def save_report(report, filepath='fixer_report.json'):
    with open(filepath, 'w') as f:
        json.dump(report, f, indent=2)
